function EssayPage({ essay, mounted, navigateTo, theme }) {
  const [titleHovered, setTitleHovered] = useState(false);
  const [initialReveal, setInitialReveal] = useState(true);
  const isFirstRender = useRef(true);
  const isTouchRef = useRef(false);
  const activeSections = essay.sections;
  const showDefinition = titleHovered || initialReveal;

  useEffect(() => {
    const duration = isFirstRender.current ? 5000 : 3000;
    isFirstRender.current = false;
    setInitialReveal(true);
    const timer = setTimeout(() => setInitialReveal(false), duration);
    return () => clearTimeout(timer);
  }, []);
  return (
    <div style={{
      maxWidth: 680,
      margin: "0 auto",
      padding: "0 clamp(16px, 4vw, 32px)",
      paddingTop: 80,
      paddingBottom: 160
    }}>
      <div
        onClick={() => navigateTo("essays")}
        style={{
          fontFamily: "'Inter', sans-serif",
          fontSize: 13,
          color: theme.textSubtle,
          cursor: "pointer",
          marginBottom: 48,
          display: "flex",
          alignItems: "center",
          gap: 8,
          transition: "color 0.3s ease",
          animation: mounted ? "fadeIn 0.6s 0.1s both" : "none"
        }}
        onMouseEnter={(e) => e.currentTarget.style.color = theme.textMuted}
        onMouseLeave={(e) => e.currentTarget.style.color = theme.textSubtle}
      >
        <span style={{ fontSize: 16 }}>←</span> Back to essays
      </div>

      <div style={{
        animation: mounted ? "fadeUp 0.8s cubic-bezier(0.16, 1, 0.3, 1) 0.15s both" : "none"
      }}>
        <div style={{
          display: "flex",
          alignItems: "center",
          gap: 12,
          marginBottom: 20
        }}>
          <span style={{
            fontFamily: "'Inter', sans-serif",
            fontSize: 12,
            color: theme.textFaint,
            fontWeight: 300
          }}>
            {essay.date}
          </span>
          <span style={{
            fontFamily: "'Inter', sans-serif",
            fontSize: 12,
            color: theme.textTiny,
            fontWeight: 300
          }}>
            ·
          </span>
          <span style={{
            fontFamily: "'Inter', sans-serif",
            fontSize: 12,
            color: theme.textFaint,
            fontWeight: 300
          }}>
            {essay.readTime}
          </span>
        </div>

        <h1
          onTouchStart={() => { isTouchRef.current = true; }}
          onMouseEnter={() => { if (!isTouchRef.current) setTitleHovered(true); }}
          onMouseLeave={() => { if (!isTouchRef.current) setTitleHovered(false); }}
          onClick={() => { if (isTouchRef.current) setTitleHovered(prev => !prev); }}
          style={{
          fontFamily: "'Syne', sans-serif",
          fontSize: "clamp(32px, 4.5vw, 48px)",
          fontWeight: 400,
          letterSpacing: "-0.02em",
          lineHeight: 1.12,
          color: theme.text,
          marginBottom: 16,
          cursor: "default",
          display: "flex",
          alignItems: "baseline",
          flexWrap: "wrap",
          gap: "0 24px"
        }}>
          <span>{essay.title}</span>
          {essay.id === "mangilik-tartip" && <span style={{
            fontFamily: "'Inter', sans-serif",
            fontSize: "clamp(12px, 1.4vw, 14px)",
            fontWeight: 300,
            color: theme.textLink,
            letterSpacing: "0.02em",
            opacity: showDefinition ? 1 : 0,
            transition: "opacity 0.5s ease",
            lineHeight: 1.5
          }}>
            /mæŋ.gɪˈlɪk tærˈtəp/{"\u00A0\u00A0"}noun [Kazakh]{"\u00A0\u00A0"}Eternal Order
          </span>}
          {essay.subtitle && <span style={{
            fontFamily: "'Inter', sans-serif",
            fontSize: "clamp(12px, 1.4vw, 14px)",
            fontWeight: 300,
            color: theme.textLink,
            letterSpacing: "0.02em",
            lineHeight: 1.5
          }}>
            {essay.subtitle}
          </span>}
        </h1>

        <div style={{
          width: 48,
          height: 1,
          background: theme.selection,
          marginBottom: 48,
          animation: mounted ? "widthGrow 0.8s cubic-bezier(0.16, 1, 0.3, 1) 0.5s both" : "none"
        }} />
      </div>

      {essay.id === "mangilik-tartip" && <div style={{
        fontFamily: "'Inter', sans-serif",
        fontSize: 13,
        lineHeight: 1.7,
        color: theme.textLink,
        fontStyle: "italic",
        fontWeight: 300,
        marginBottom: 48,
        paddingLeft: 16,
        borderLeft: "2px solid " + theme.disclaimerBorder,
        animation: mounted ? "fadeUp 0.8s cubic-bezier(0.16, 1, 0.3, 1) 0.35s both" : "none"
      }}>
        Nothing written here is a claim against anyone{"\u2019"}s faith. I hold deep respect for any and every belief. I am only describing what I see, with the language available to me.
      </div>}

      <div style={{
        animation: mounted ? "fadeUp 0.8s cubic-bezier(0.16, 1, 0.3, 1) 0.4s both" : "none"
      }}>
        {activeSections.map((section, si) => (
          <div key={si}>
            {section.heading && <h2 style={{
              fontFamily: "'Syne', sans-serif",
              fontSize: 28,
              fontWeight: 400,
              letterSpacing: "-0.01em",
              color: theme.textHL,
              marginTop: si === 0 ? 0 : 56,
              marginBottom: 32
            }}>
              {section.heading}
            </h2>}
            {section.paragraphs.map((paragraph, pi) => (
              <p key={pi} style={{
                fontFamily: "'Inter', sans-serif",
                fontSize: 16,
                lineHeight: 1.85,
                color: theme.textMuted,
                fontWeight: 300,
                marginBottom: 28,
                letterSpacing: "0.005em"
              }}>
                {renderText(paragraph, theme)}
              </p>
            ))}
            {section.image && (
              <img src={section.image} alt="" style={{
                width: "100%",
                maxWidth: 560,
                borderRadius: 8,
                marginTop: 8,
                marginBottom: 8,
                display: "block"
              }} />
            )}
          </div>
        ))}
      </div>

      {essay.disclaimer && <div style={{
        fontFamily: "'Inter', sans-serif",
        fontSize: 13,
        color: theme.textFaint,
        fontStyle: "italic",
        fontWeight: 300,
        marginTop: 48,
        textAlign: "right"
      }}>
        {essay.disclaimer}
      </div>}

      <div style={{
        height: 1,
        background: theme.hlBg,
        margin: "64px 0 32px"
      }} />

      <div style={{
        display: "flex",
        justifyContent: "space-between",
        alignItems: "center"
      }}>
        <div
          onClick={() => navigateTo("essays")}
          style={{
            fontFamily: "'Inter', sans-serif",
            fontSize: 13,
            color: theme.textSubtle,
            cursor: "pointer",
            transition: "color 0.3s ease"
          }}
          onMouseEnter={(e) => e.currentTarget.style.color = theme.textMuted}
          onMouseLeave={(e) => e.currentTarget.style.color = theme.textSubtle}
        >
          ← All essays
        </div>
      </div>
      <SiteFooter theme={theme} />
    </div>
  );
}


function AboutPage({ mounted, theme }) {
  return (
    <div style={{
      maxWidth: 680,
      margin: "0 auto",
      padding: "0 clamp(16px, 4vw, 32px)",
      paddingTop: 80,
      paddingBottom: 160
    }}>
      <div style={{
        animation: mounted ? "fadeUp 0.8s cubic-bezier(0.16, 1, 0.3, 1) 0.15s both" : "none"
      }}>
        <h2 style={{
          fontFamily: "'Syne', sans-serif",
          fontSize: "clamp(36px, 5vw, 48px)",
          fontWeight: 500,
          letterSpacing: "-0.03em",
          marginBottom: 48,
          color: theme.text
        }}>
          About
        </h2>

        {["I'm 18, based in Almaty, Kazakhstan. I spend most of my time on machine learning, mathematics, and physics.", "I'm a CMS-ranked boxer, nationally ranked mountaineer and trail runner. CMS, Candidate for Master of Sport, is the competitive classification system across post-Soviet countries.", "I'm interested in how the same mathematical structures (differential equations, optimization, control theory) keep appearing across physics, economics, and logistics. I think that pattern means something.", "Writing is how I organize my thinking. These will tend to be long. I follow the idea until it's done."].map((text, i) => (
          <p key={i} style={{
            fontFamily: "'Inter', sans-serif",
            fontSize: 16,
            lineHeight: 1.85,
            color: theme.textMuted,
            fontWeight: 300,
            marginBottom: 24,
            letterSpacing: "0.005em"
          }}>
            {text}
          </p>
        ))}

        <SiteFooter theme={theme} />
      </div>
    </div>
  );
}
